SELECT count(*)
FROM TBL_OAUTH_MEMBER
WHERE MEMBER_EMAIL = #{memberEmail}

SELECT ID, MEMBER_EMAIL, MEMBER_PASSWORD, MEMBER_NAME
FROM TBL_OAUTH_MEMBER
WHERE ID = #{id}

SELECT ID, MEMBER_EMAIL, MEMBER_PASSWORD, MEMBER_NAME
FROM TBL_OAUTH_MEMBER
WHERE MEMBER_EMAIL = #{memberEmail}
  AND MEMBER_PASSWORD = #{memberPassword}

UPDATE TBL_OAUTH_MEMBER
SET MEMBER_PASSWORD = #{memberPassword}, MEMBER_NAME = #{memberName}
WHERE ID = #{id}
